import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testNewFormat() throws Exception {
        char delimiter = ';';
        CSVFormat format = CSVFormat.newFormat(delimiter);

        assertNotNull(format);

        // Using reflection to check private fields
        var delimiterField = CSVFormat.class.getDeclaredField("delimiter");
        delimiterField.setAccessible(true);
        assertEquals(delimiter, delimiterField.getChar(format));

        var quoteCharacterField = CSVFormat.class.getDeclaredField("quoteCharacter");
        quoteCharacterField.setAccessible(true);
        assertNull(quoteCharacterField.get(format));

        var quoteModeField = CSVFormat.class.getDeclaredField("quoteMode");
        quoteModeField.setAccessible(true);
        assertNull(quoteModeField.get(format));

        var commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);
        assertNull(commentMarkerField.get(format));

        var escapeCharacterField = CSVFormat.class.getDeclaredField("escapeCharacter");
        escapeCharacterField.setAccessible(true);
        assertNull(escapeCharacterField.get(format));

        var ignoreSurroundingSpacesField = CSVFormat.class.getDeclaredField("ignoreSurroundingSpaces");
        ignoreSurroundingSpacesField.setAccessible(true);
        assertFalse(ignoreSurroundingSpacesField.getBoolean(format));

        var allowMissingColumnNamesField = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        allowMissingColumnNamesField.setAccessible(true);
        assertFalse(allowMissingColumnNamesField.getBoolean(format));

        var recordSeparatorField = CSVFormat.class.getDeclaredField("recordSeparator");
        recordSeparatorField.setAccessible(true);
        assertNull(recordSeparatorField.get(format));

        var nullStringField = CSVFormat.class.getDeclaredField("nullString");
        nullStringField.setAccessible(true);
        assertNull(nullStringField.get(format));

        var headerField = CSVFormat.class.getDeclaredField("header");
        headerField.setAccessible(true);
        assertNull(headerField.get(format));

        var skipHeaderRecordField = CSVFormat.class.getDeclaredField("skipHeaderRecord");
        skipHeaderRecordField.setAccessible(true);
        assertFalse(skipHeaderRecordField.getBoolean(format));
    }
}
